class ETGSalesInvoiceCreateDialog extends RunBase
{
    DialogField accountNum;
    DialogField nameOfCust, mobileNoOfCust, nrcOfCust, addressOfCust, currency;
    DialogField dateSO;
    DialogField site;
    DialogField warehouse;
    DialogField itemNum;
    DialogField qtyUOM;
    DialogField qtyDF;
    DialogField connectionType;
    DialogField depositAmount;
    DialogField modeOfPayment;
    DialogField businessSegment;
    DialogField methodOfPayment;
    DialogField totalOfInvoice, totalOfInvVal;
    DialogField inventBatchId;
    DialogField salesPrice, salesPriceVal;
    DialogField taxItemGroup;
    DialogField taxGroup;

    FormBuildStringControl currencyControl;
    FormBuildStringControl itemIdControl;
    FormBuildRealControl qtyControl;
    FormBuildRealControl unitPriceControl;
    FormBuildStringControl taxGroupControl;
    FormBuildComboBoxControl connectionTypeControl;

    //FormRadioControl formRadioControl;

    CustAccount custAccount;
    ETGNameOfCust nameOfCustLoc;
    ETGMobileNumberOfCust mobileNoOfCustLoc;
    ETGNRCOfCust nrcOfCustLoc;
    ETGAddressOfCust addressOfCustLoc;
    SalesShippingDateRequested dateSOH;
    InventSiteId inventSiteId;
    InventLocationId inventLocationId;
    ETGBusinessSegment businessSegmentLoc;
    CustPaymMode methodOfPaymentLoc;
    ItemIdSmall itemIdSmall;
    SalesUnit qtyUOMLoc;
    SalesOrderedQty qty;
    SalesPrice salesPriceLoc;
    ETGConnectionType connectionTypeLoc;
    ETGDepositAmount depositAmountLoc;
    SalesLineAmount totalOfInvoiceLoc;
    InventBatchId inventBatchIdLoc;
    CustCurrencyCode currencyCodeLoc;
    TaxItemGroup taxItemGroupLoc;
    TaxGroup taxGroupLoc;

    #define.FieldNoTmp(600)

}

