/// <summary>
/// 
/// </summary>
/// <param name = "_packedclass"></param>
/// <returns></returns>
public boolean unpack(container _packedclass)
{
    return true;
}

public Object dialog()
{
    Dialog dialog;
    Set enumSet = new Set(Types::Enum);

    DialogGroup headers;
    DialogGroup lines;
    dialog = super();

    dialog.caption("Simple Sales");

    headers = dialog.addGroup("Sales header details");
    accountNum = dialog.addField(extendedTypeStr(CustAccount), "Customer");
    currencyControl = accountNum.control();
    currencyControl.registerOverrideMethod(methodStr(FormStringControl, modified), methodStr(ETGSalesInvoiceCreateDialog,modifyCustomer), this);

    nameOfCust = dialog.addField(extendedTypeStr(ETGNameOfCust),"Name of cust");
    mobileNoOfCust = dialog.addField(extendedTypeStr(ETGMobileNumberOfCust),"Mobile No Of Cust");
    nrcOfCust = dialog.addField(extendedTypeStr(ETGNRCOfCust),"NRC Of Cust");
    addressOfCust = dialog.addField(extendedTypeStr(ETGAddressOfCust),"Address Of Cust");
    currency = dialog.addField(extendedTypeStr(CustCurrencyCode),"Currency");
    dateSO = dialog.addFieldValue(extendedTypeStr(SalesShippingDateRequested),"Date");
    site = dialog.addField(extendedTypeStr(InventSiteId), "Site");
    warehouse = dialog.addField(extendedTypeStr(InventLocationId),"Warehouse");
    inventBatchId = dialog.addField(extendedTypeStr(InventBatchId), "Batch number");
    businessSegment = dialog.addField(enumStr(ETGBusinessSegment), "Business Segment");
    //formRadioControl = businessSegment.control();
    methodOfPayment = dialog.addField(extendedTypeStr(CustPaymMode), "Method Of Payment");

    lines = dialog.addGroup("Sales line details");
    itemNum = dialog.addField(extendedTypeStr(ItemIdSmall));
    salesPriceVal = dialog.addField(extendedTypeStr(SalesPrice), "Unit price");
    unitPriceControl = salesPriceVal.control();
    unitPriceControl.registerOverrideMethod(methodStr(FormRealControl, modified), methodStr(ETGSalesInvoiceCreateDialog,modifyUnitPrice), this);
    itemIdControl = itemNum.control();
    itemIdControl.registerOverrideMethod(methodStr(FormStringControl, modified), methodStr(ETGSalesInvoiceCreateDialog,modifyItemId), this);
    //itemIdControl.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGSalesInvoiceCreateDialog,itemIdLookup), this);

    qtyDF = dialog.addField(extendedTypeStr(SalesOrderedQty),"Qty");
    qtyControl = qtyDF.control();
    qtyControl.registerOverrideMethod(methodStr(FormRealControl, modified), methodStr(ETGSalesInvoiceCreateDialog,modifyQty), this);
    qtyUOM = dialog.addField(extendedTypeStr(SalesUnit),"Qty UOM");
    taxItemGroup = dialog.addField(extendedTypeStr(TaxItemGroup),"Item Sales Tax Group");
    taxGroup = dialog.addField(extendedTypeStr(TaxGroup),"Sales Tax Group");
    taxGroupControl = taxGroup.control();
    taxGroupControl.registerOverrideMethod(methodStr(FormRealControl, modified), methodStr(ETGSalesInvoiceCreateDialog,modifyTaxGroup), this);
    //salesPrice = dialog.addField(extendedTypeStr(SalesPrice), "Unit price");
    connectionType = dialog.addField(enumStr(ETGConnectionType), "Connection Type");
    connectionTypeControl = connectionType.control();
    connectionTypeControl.registerOverrideMethod(methodStr(FormComboBoxControl, selectionChange), methodStr(ETGSalesInvoiceCreateDialog,modifyConnectionType), this);
    depositAmount = dialog.addField(extendedTypeStr(ETGDepositAmount), "Deposit Amount");

    totalOfInvVal = dialog.addField(extendedTypeStr(SalesLineAmount), "Total Of Invoice");

    return dialog;
}

/// <summary>
/// 
/// </summary>
/// <returns></returns>
public boolean getFromDialog()
{
    custAccount = accountNum.value();
    nameOfCustLoc = nameOfCust.value();
    mobileNoOfCustLoc = mobileNoOfCust.value();
    nrcOfCustLoc = nrcOfCust.value();
    addressOfCustLoc = addressOfCust.value();
    currencyCodeLoc = currency.value();
    inventSiteId = site.value();
    inventLocationId = warehouse.value();
    dateSOH = dateSO.value();
    inventBatchIdLoc = inventBatchId.value();
    businessSegmentLoc = businessSegment.value();
    methodOfPaymentLoc = methodOfPayment.value();
    itemIdSmall = itemNum.value();
    qtyUOMLoc = qtyUOM.value();
    qty = qtyDF.value();
    salesPriceLoc = salesPriceVal.value();
    depositAmountLoc = depositAmount.value();
    connectionTypeLoc = connectionType.value();
    taxItemGroupLoc = taxItemGroup.value();
    taxGroupLoc = taxGroup.value();
    totalOfInvoiceLoc = totalOfInvoice.value();
    return super();
}

public void run()
{
    SalesTable salesTable;
    NumberSeq NumberSeq;
    SalesId sid;
    SalesLine sl;
    InventDim inventDim;
    SalesFormLetter salesFormLetter;
    ETG_SalesTableTrade             salesTableTrade;
    ETG_BillOfLading                ETGBilloflading;
    CustInvoiceJour custInvoiceJour;
    InventTable inventTable;
    WMSLocation wmsLocation;
    ;
    ttsbegin;
    NumberSeq = NumberSeq::newGetNum(SalesParameters::numRefSalesId() , true);
    sid = NumberSeq.num();
    salesTable.SalesId = sid;
    salesTable.ShippingDateRequested = dateSOH;
    salesTable.ReceiptDateRequested = dateSOH;
    salesTable.initValue();
    salesTable.CustAccount = custAccount;
    salesTable.ETGBusinessSegment = businessSegmentLoc;        
    salesTable.initFromCustTable();
    salesTable.CurrencyCode = currencyCodeLoc;
    salesTable.InventSiteId = inventSiteId;
    salesTable.InventLocationId = inventLocationId;
    salesTable.PaymMode = methodOfPaymentLoc;
    salesTable.insert();

    salesTableTrade.clear();
    salesTableTrade.SalesId = salesTable.SalesId;
    salesTableTrade.CountryOfFinalDestination = "";
    salesTableTrade.Declaration = "";
    salesTableTrade.Remarks = "";
    salesTableTrade.PortOfLoading = "";
    salesTableTrade.PortOfLoadingDesc = "";
    salesTableTrade.PortOfDischarge = "";
    salesTableTrade.PortOfDischargeDesc = "";
    salesTableTrade.ETGNameOfCust = nameOfCustLoc;
    salesTableTrade.ETGMobileNumberOfCust = mobileNoOfCustLoc;
    salesTableTrade.ETGNRCOfCust = nrcOfCustLoc;
    salesTableTrade.ETGAddressOfCust = addressOfCustLoc;
    salesTableTrade.insert();

    ETGBilloflading.clear();
    ETGBilloflading.SalesId   = salesTable.SalesId;
    ETGBilloflading.CarrierCode = "";
    ETGBilloflading.NumberOfBags = "";
    ETGBilloflading.NumberOfContainers = 0;
    ETGBilloflading.insert();

    //Create the Sales Line with the created Sales Order
    container itemIdSmallCon;
    itemIdSmallCon = str2con(itemIdSmall);
    select * from inventTable
                where inventTable.itemId == itemIdSmall;

    sl.clear();
    sl.initFromSalesTable(salesTable);
    sl.SalesId = sid;
    sl.ItemId = inventTable.ItemId;

    //  Initialize InventDim
    sl.initFromInventTable(InventTable::find(sl.ItemId));

    if(Inventlocation::find(inventLocationId).InventLocationId != "")
    {
        inventdim.InventSiteId = InventLocation::find(inventLocationId).InventSiteId;
        inventdim.InventLocationId = Inventlocation::find(inventLocationId).InventLocationId;
    }
    sl.SalesQty = qty;
    sl.SalesUnit = qtyUOMLoc;

    select * from wmsLocation where wmsLocation.inventLocationId == inventLocationId;

    inventDim.wMSLocationId = wmsLocation.wMSLocationId;
    inventDim.inventBatchId = inventBatchIdLoc;
    sl.InventDimId = InventdIm::findOrCreate(inventdim).inventDimId;

    sl.CreateLine(NoYes::Yes,NoYes::Yes,NoYes::Yes,NoYes::Yes,NoYes::Yes,NoYes::Yes);
    sl.SalesPrice = salesPriceLoc;//InventTableModule::find(inventTable.ItemId, ModuleInventPurchSales::Sales).Price;
    sl.TaxGroup = taxGroupLoc;
    sl.TaxItemGroup = taxItemGroupLoc;
    sl.ETGDepositAmount = depositAmountLoc;
    sl.ETGConnectionType = connectionTypeLoc;
    sl.LineAmount= sl.calcLineAmount();

    sl.update();

    // ttscommit;
   // info("Sales Order Created with Line");
    SalesTable salesTableOrg;
    salesTableOrg = SalesTable::find(sid);
    salesFormLetter = SalesFormLetter::construct(DocumentStatus::Confirmation);
    salesFormLetter.update(salesTableOrg, systemDateGet(), SalesUpdate::All);

    //Post the delivery
    salesFormLetter = SalesFormLetter::construct(DocumentStatus::PackingSlip);
    salesFormLetter.update(SalesTable::find(sid));
    // salesFormLetter.progressHide();                                // Hide the progress bar.
    salesFormLetter.update(salesTableOrg,                             // SalesTable
    SystemDateGet(),                        // Delivery date
    SalesUpdate::All,                // Quantity to update (SpecQty)
    AccountOrder::None,                     // AccountOrder
    false,                                  // Proforma only?
    false);                                 // Printout?

    //Post the Sales Order Invoice
    SalesFormLetter::construct(DocumentStatus::Invoice).update(SalesTable::find(sid));;
    //salesFormLetter.update(salesTableOrg, systemDateGet(), SalesUpdate::All, AccountOrder::None, NoYes::No, NoYes::No, NoYes::No, NoYes::Yes);
    ttscommit;

    ttsbegin;
    select forupdate custInvoiceJour where custInvoiceJour.SalesId == salesTable.SalesId;
    custInvoiceJour.ETG_BLnumber = "N004-00001";
    custInvoiceJour.ETG_BLDate = dateSOH;
    //custInvoiceJour.InvoiceDate = dateSOH;
    custInvoiceJour.update();
    ttscommit;
    info(strFmt("%1 Sales Order invoice is created", salesTable.SalesId));


}

/// <summary>
///
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyCustomer(FormStringControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr())
        {
            CustTable custTable = CustTable::find(_control.valueStr());

            currency.value(custTable.Currency);
        }
        else
        {
            currency.value("");
        }
    }
    return ret;
}

/// <summary>
/// 
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyItemId(FormStringControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr())
        {
            InventTableModule inventTableModule = InventTableModule::find(_control.valueStr(), ModuleInventPurchSales::Sales);

            salesPriceVal.value(inventTableModule.Price);
        }
        else
        {
            salesPriceVal.value("");
        }
    }
    return ret;
}

