/// <summary>
/// 
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyQty(FormRealControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr())
        {
            //InventTableModule inventTableModule = InventTableModule::find(itemNum.value(), ModuleInventPurchSales::Sales);
            real priceA = salesPriceVal.value() * _control.realValue();
            if(taxGroup.value())
            {
                TaxGroupData taxGroupDataLoc;

                select * from taxGroupDataLoc where taxGroupDataLoc.TaxGroup == taxGroup.value();
                TaxValue tacValueLoc = taxGroupDataLoc.showTaxValue();
                if(tacValueLoc)
                {
                    real totalInvV = salesPriceVal.value() * qtyDF.value();
                    real priceBC = totalInvV * tacValueLoc/100;
                    real PriceI = priceBC + priceA;
                    totalOfInvVal.value(PriceI);
                }
                else
                {
                    totalOfInvVal.value(priceA);
                }
            }
            else
            {
                totalOfInvVal.value(priceA);
            }

        }
        else
        {
            totalOfInvVal.value("");
        }
    }
    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyUnitPrice(FormRealControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr())
        {
            //InventTableModule inventTableModule = InventTableModule::find(itemNum.value(), ModuleInventPurchSales::Sales);
            real priceB = qtyDF.value() * _control.realValue();

            if(taxGroup.value())
            {
                TaxGroupData taxGroupDataLocUnit;

                select * from taxGroupDataLocUnit where taxGroupDataLocUnit.TaxGroup == taxGroup.value();
                TaxValue tacValueLocUnit = taxGroupDataLocUnit.showTaxValue();
                if(tacValueLocUnit)
                {
                    real totalInvU = salesPriceVal.value() * qtyDF.value();
                    real priceBU = totalInvU * tacValueLocUnit/100;
                    real PriceIU = priceBU + priceB;
                    totalOfInvVal.value(PriceIU);
                }
                else
                {
                    totalOfInvVal.value(priceB);
                }
            }
            else
            {
                totalOfInvVal.value(priceB);
            }
        }
        else
        {
            totalOfInvVal.value("");
        }
    }
    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyTaxGroup(FormStringControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr())
        {
            TaxGroupData taxGroupData;

            select * from taxGroupData where taxGroupData.TaxGroup == _control.valueStr();
            TaxValue tacValue = taxGroupData.showTaxValue();
            if(tacValue)
            {
                real totalInv = salesPriceVal.value() * qtyDF.value();
                real priceB = totalInv * tacValue/100;
                real calculation = totalInv + priceB;
                totalOfInvVal.value(calculation);
            }
            else
            {
                real totalInvoice = salesPriceVal.value() * qtyDF.value();
                totalOfInvVal.value(totalInvoice);
            }
        }
        else
        {
            totalOfInvVal.value();
        }
    }
    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_control"></param>
/// <returns></returns>
public boolean modifyConnectionType(FormComboBoxControl _control)
{
    boolean ret = _control.modified();
    if(ret)
    {
        if(_control.valueStr() != enum2Str(ETGConnectionType::NewConnectionorCylinder))
        {
            depositAmount.allowEdit(false);
            depositAmount.value("");
        }
        else
        {
            depositAmount.allowEdit(true);
        }
    }
    return ret;
}

/// <summary>
/// 
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGSalesInvoiceCreateDialog salesInvoiceCreateDialog = new ETGSalesInvoiceCreateDialog();

    if(salesInvoiceCreateDialog.prompt())
    {
        salesInvoiceCreateDialog.run();
    }
}
